import boto3
import json

class SQSPublisher:
    def __init__(self, queue_url):
        self.sqs = boto3.client('sqs')
        self.queue_url = queue_url

    def send_message(self, user_data):
        message = {
            'data': user_data
        }
        response = self.sqs.send_message(
            QueueUrl=self.queue_url,
            MessageBody=json.dumps(message),
            MessageAttributes={
                'pii': {
                    'StringValue': 'true',
                    'DataType': 'String'
                }
            }
        )

# Usage
publisher = SQSPublisher('your_queue_url_here')
user_data = {
    'name': 'John Doe',
    'email': 'johndoe@example.com',
    'phone': '123-456-7890',
    'address': '123 Main St'
}
publisher.send_message(user_data)